package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
    }

    @Test
    void testPrintCreatesCSVPrinter() throws IOException {
        try (MockedConstruction<OutputStreamWriter> mockedWriter = Mockito.mockConstruction(OutputStreamWriter.class);
             MockedConstruction<CSVPrinter> mockedPrinter = Mockito.mockConstruction(CSVPrinter.class)) {

            CSVPrinter printer = csvFormat.print(mockFile, charset);

            assertNotNull(printer);
            // Verify that OutputStreamWriter was constructed with FileOutputStream and Charset
            assertEquals(1, mockedWriter.constructed().size());
            OutputStreamWriter writer = mockedWriter.constructed().get(0);
            assertNotNull(writer);

            // Verify CSVPrinter was constructed with the writer and this CSVFormat instance
            assertEquals(1, mockedPrinter.constructed().size());
            CSVPrinter csvPrinter = mockedPrinter.constructed().get(0);
            assertNotNull(csvPrinter);
            // The returned printer should be the mocked one
            assertSame(csvPrinter, printer);
        }
    }

    @Test
    void testPrintThrowsIOException() {
        // We simulate a FileOutputStream constructor throwing IOException by mocking FileOutputStream class
        // However, FileOutputStream is final and cannot be mocked easily with Mockito 3 without inline mocking enabled.
        // So instead, we test that the method propagates IOException by passing an invalid File object or charset is null.
        assertThrows(NullPointerException.class, () -> csvFormat.print(mockFile, null));
    }
}
